%% SDPE MATLAB initialization script
% Project: DPS CLLLC / DAB MATLAB Simulink SIL
% Generated by tools/SDPE_v2. Do not edit generated variables directly.

% Notes:
%   PC SIL runtime, BUILD_LEVEL and virtual advanced-PWM settings layered over the common CLLLC contract.

%% Project metadata
DPS_CLLLC_SIM_SDPE_PROJECT_ID = 'dps_clllc_simulate';

DPS_CLLLC_SIM_SDPE_PROJECT_SUITE = 'dps_clllc';

DPS_CLLLC_SIM_SDPE_PROJECT_VERSION = '1.0.0';

DPS_CLLLC_SIM_SDPE_PROJECT_UPDATED_AT = '2026-07-19';

%% Simulation
% Enable PC/SIL-specific commissioning behavior.
SPECIFY_PC_ENVIRONMENT = true;

%% Controller Mode
% 1: open loop; 2: current loop; 3: voltage loop; 4: voltage/current parallel competition loop.
% Options: (1), (2), (3), (4)
BUILD_LEVEL = 1;

%% Requirement bindings
% Virtual ePWM clock.
CLLLC_TIMER_CLOCK_HZ = 100000000.0;

% PWM periods per ADC/control update.
CLLLC_PWM_CYCLES_PER_CONTROL = 2;

% Nominal controller frequency.
CONTROLLER_FREQUENCY = CLLLC_F_RESONANT_HZ / CLLLC_PWM_CYCLES_PER_CONTROL;

% Virtual advanced-PWM base period.
CLLLC_NOMINAL_PERIOD_TICKS = CLLLC_TIMER_CLOCK_HZ / CLLLC_F_RESONANT_HZ;

% PC scheduler tick.
CTRL_SYSTEM_TICK_HZ = 1000;

% Short SIL CiA402 transition delay.
CTRL_STARTUP_DELAY_MS = 2;

% Virtual ADC reference.
CTRL_ADC_VOLTAGE_REF = 3.3;

% Virtual ADC resolution.
CTRL_ADC_BITS = 12;

%% Local helpers
function value = sdpe_select(condition, true_value, false_value)
if condition
    value = true_value;
else
    value = false_value;
end
end
